import{_ as s}from"./plugin-vue_export-helper-c27b6911.js";import{r as t,o,c as i,a as e,b as a,d as r,e as d}from"./app-ae06ed2d.js";const n={},l=d('<h1 id="elasticsearch-面试" tabindex="-1"><a class="header-anchor" href="#elasticsearch-面试" aria-hidden="true">#</a> Elasticsearch 面试</h1><h2 id="elasticsearch-简介" tabindex="-1"><a class="header-anchor" href="#elasticsearch-简介" aria-hidden="true">#</a> Elasticsearch 简介</h2><h3 id="什么是-elasticsearch" tabindex="-1"><a class="header-anchor" href="#什么是-elasticsearch" aria-hidden="true">#</a> 什么是 ElasticSearch</h3>',3),h={href:"https://github.com/elastic/elasticsearch",target:"_blank",rel:"noopener noreferrer"},p={href:"https://github.com/elastic/elasticsearch",target:"_blank",rel:"noopener noreferrer"},g={href:"https://github.com/apache/lucene-solr",target:"_blank",rel:"noopener noreferrer"},f=d(`<p>ElasticSearch 可以视为一个文档存储，它<strong>将复杂数据结构序列化为 JSON 存储</strong>。</p><p><strong>ElasticSearch 是近实时（Near Realtime，缩写 NRT）的全文搜索</strong>。近实时是指：</p><ul><li>从写入数据到数据可以被搜索，存在较小的延迟（大概是 1s）。</li><li>基于 Elasticsearch 执行搜索和分析可以达到秒级。</li></ul><h2 id="elasticsearch-架构" tabindex="-1"><a class="header-anchor" href="#elasticsearch-架构" aria-hidden="true">#</a> Elasticsearch 架构</h2><h3 id="es-更新操作是如何执行的" tabindex="-1"><a class="header-anchor" href="#es-更新操作是如何执行的" aria-hidden="true">#</a> ES 更新操作是如何执行的？</h3><p>写入操作包含：单文档写入（index、create、update、delete）和批量写入（bulk）。</p><ol><li>客户端选择一个 node 发送请求过去，如果没有指定路由/协调节点，这个 node 就是 <code>coordinating node</code> （协调节点）。</li><li><code>coordinating node</code> 对 document 进行<strong>路由</strong>，将请求转发给对应的 node（有 primary shard）。</li><li>实际的 node 上的 <code>primary shard</code> 处理请求，然后将数据同步到 <code>replica node</code> 。</li><li><code>coordinating node</code> 等待 <code>primary node</code> 和所有 <code>replica node</code> 执行成功后，就返回响应结果给客户端。</li></ol><figure><img src="https://github.com/doocs/advanced-java/raw/main/docs/high-concurrency/images/es-write.png" alt="es-write" tabindex="0" loading="lazy"><figcaption>es-write</figcaption></figure><p>第 2 步中的文档是如何路由的呢？</p><p>借助路由算法计算的对应的分片。路由算法就是：先根据 <code>_routing</code>（通常是 <code>_doc</code> 和 <code>_id</code>）进行 hash 计算，再根据主分片数取模。</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>shardNo = hash(_routing) % (num_of_primary_shards)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="elasticsearch-index-操作的过程" tabindex="-1"><a class="header-anchor" href="#elasticsearch-index-操作的过程" aria-hidden="true">#</a> Elasticsearch index 操作的过程</h4><p>协调节点默认使用文档 ID 参与计算（也支持通过 routing），以便为路由提供合适的分片。</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>shard = hash(document_id) % (num_of_primary_shards)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><p>当分片所在的节点接收到来自协调节点的请求后，会将请求写入到 MemoryBuffer，然后定时（默认是每隔 1 秒）写入到 Filesystem Cache，这个从 MemoryBuffer 到 Filesystem Cache 的过程就叫做 refresh；</p></li><li><p>当然在某些情况下，存在 Memory Buffer 和 Filesystem Cache 的数据可能会丢失，Elasticsearch 是通过 translog 的机制来保证数据的可靠性的。其实现机制是接收到请求后，同时也会写入到 translog 中 ，当 Filesystem cache 中的数据写入到磁盘中时，才会清除掉，这个过程叫做 flush；</p></li><li><p>在 flush 过程中，内存中的缓冲将被清除，内容被写入一个新段，段的 fsync 将创建一个新的提交点，并将内容刷新到磁盘，旧的 translog 将被删除并开始一个新的 translog。</p></li><li><p>flush 触发的时机是定时触发（默认 30 分钟）或者 translog 变得太大（默认为 512M）时；</p></li></ul><figure><img src="https://www.elastic.co/guide/en/elasticsearch/reference/current/images/data_processing_flow.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>补充：关于 Lucene 的 Segement：</p><ul><li><p>Lucene 索引是由多个段组成，段本身是一个功能齐全的倒排索引。</p></li><li><p>段是不可变的，允许 Lucene 将新的文档增量地添加到索引中，而不用从头重建索引。</p></li><li><p>对于每一个搜索请求而言，索引中的所有段都会被搜索，并且每个段会消耗 CPU 的时钟周、文件句柄和内存。这意味着段的数量越多，搜索性能会越低。</p></li><li><p>为了解决这个问题，Elasticsearch 会合并小段到一个较大的段，提交新的合并段到磁盘，并删除那些旧的小段。</p></li></ul>`,18),u=e("p",null,"参考：",-1),m={href:"https://www.elastic.co/guide/en/elasticsearch/reference/current/preload-data-to-file-system-cache.html",target:"_blank",rel:"noopener noreferrer"},b={href:"https://blog.devgenius.io/elasticsearch-solution-to-searching-71116220c82f",target:"_blank",rel:"noopener noreferrer"},_=d('<h4 id="elasticsearch-update-和-delete-操作的过程" tabindex="-1"><a class="header-anchor" href="#elasticsearch-update-和-delete-操作的过程" aria-hidden="true">#</a> Elasticsearch update 和 delete 操作的过程</h4><p>Elasticsearch 的 document 的物理存储是 Luncene segment，而 segment 不允许变更。那么，如何处理删除和更新呢？</p><ul><li>如果是删除操作，commit 的时候会生成一个 <code>.del</code> 文件，里面将某个 doc 标识为 <code>deleted</code> 状态，那么搜索的时候根据 <code>.del</code> 文件就知道这个 doc 是否被删除了。</li><li>如果是更新操作，就是将原来的 doc 标识为 <code>deleted</code> 状态，然后新写入一条数据。</li><li><code>memory buffer</code> 每 <code>refresh</code> 一次，就会产生一个 <code>segment file</code>。由于，默认每秒刷新 1 次，即每秒产生一个 <code>segment file</code>，这样下来 <code>segment file</code> 会越来越多。ES 会定期执行 merge 操作，将多个 <code>segment file</code> 合并成一个。合并时会将标识为 <code>deleted</code> 的 doc 给<strong>物理删除掉</strong>，然后将新的 <code>segment file</code> 写入磁盘，这里会写一个 <code>commit point</code>，标识所有新的 <code>segment file</code>，然后打开 <code>segment file</code> 供搜索使用，同时删除旧的 <code>segment file</code>。</li></ul><h3 id="es-查询操作是如何执行的" tabindex="-1"><a class="header-anchor" href="#es-查询操作是如何执行的" aria-hidden="true">#</a> ES 查询操作是如何执行的？</h3><p>在 Elasticsearch 中，搜索一般分为两个阶段，query 和 fetch 阶段。可以简单的理解，query 阶段确定要取哪些 doc，fetch 阶段取出具体的 doc。</p><ol><li>客户端发送请求到<strong>任意</strong>一个 node，这个 node 成为 <code>coordinate node</code>。<code>coordinate node</code> 创建一个大小为 from + size 的优先级队列用来存放结果。</li><li><code>coordinate node</code> 将请求广播到<strong>所有</strong>的 shard（<code>primary shard</code> 或 <code>replica shard</code> 都可以）。</li><li>query phase：每个 shard 在内部执行搜索请求，执行结果存到自身内部的大小同样为 from+size 的优先级队列里，然后将结果返回给 <code>coordinate node</code>，<code>coordinate node</code> 对数据进行汇总处理：合并、排序、分页，产生最终结果。</li><li>fetch phase：<code>coordinate node</code> 根据 <code>doc id</code> 去各个节点上 fetch（拉取）实际的 <code>document</code> 数据，最终返回给客户端。</li></ol><p>由以上流程可知：每个 shard 要扫描 <code>from + size</code> 条数据；而协调节点需要接收并处理 <code>(from + size) * primary_shard_num</code> 条数据量。一旦 from 或 size 过大，计算量也会很大，耗时很高。因此，ES 默认限制数据结果窗口大小为 10000（可以通过 <code>index.max_result_window</code> 调整）。——这就是为什么 ES 存在深分页问题。</p><p>此外，需要注意的是：搜索的时候，查询的是 Filesystem Cache 中的数据；而存在于 Memory Buffer 中，还未来得及刷新的数据，是不可见的。由于，默认刷新时间为 1 秒，这就是为什么 ES 被称为近实时搜索的原因。</p><figure><img src="https://pic2.zhimg.com/80/v2-4c25616e623de2aee23bd63ec22a5bfd_720w.jpg" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h3 id="写数据底层原理" tabindex="-1"><a class="header-anchor" href="#写数据底层原理" aria-hidden="true">#</a> 写数据底层原理</h3>',10),x={href:"https://github.com/doocs/advanced-java/blob/main/docs/high-concurrency/images/es-write-detail.png",target:"_blank",rel:"noopener noreferrer"},y=e("img",{src:"https://github.com/doocs/advanced-java/raw/master/docs/high-concurrency/images/es-write-detail.png",alt:"es-write-detail",tabindex:"0",loading:"lazy"},null,-1),E=e("figcaption",null,"es-write-detail",-1),v=d('<p>先写入内存 buffer，在 buffer 里的时候数据是搜索不到的；同时将数据写入 translog 日志文件。</p><p>如果 buffer 快满了，或者到一定时间，就会将内存 buffer 数据 <code>refresh</code> 到一个新的 <code>segment file</code> 中，但是此时数据不是直接进入 <code>segment file</code> 磁盘文件，而是先进入 <code>os cache</code> 。这个过程就是 <code>refresh</code> 。</p><p>每隔 1 秒钟，es 将 buffer 中的数据写入一个<strong>新的</strong> <code>segment file</code> ，每秒钟会产生一个<strong>新的磁盘文件</strong> <code>segment file</code> ，这个 <code>segment file</code> 中就存储最近 1 秒内 buffer 中写入的数据。</p><p>但是如果 buffer 里面此时没有数据，那当然不会执行 refresh 操作，如果 buffer 里面有数据，默认 1 秒钟执行一次 refresh 操作，刷入一个新的 segment file 中。</p><p>操作系统里面，磁盘文件其实都有一个东西，叫做 <code>os cache</code> ，即操作系统缓存，就是说数据写入磁盘文件之前，会先进入 <code>os cache</code> ，先进入操作系统级别的一个内存缓存中去。只要 <code>buffer</code> 中的数据被 refresh 操作刷入 <code>os cache</code> 中，这个数据就可以被搜索到了。</p><p>为什么叫 es 是<strong>准实时</strong>的？ <code>NRT</code> ，全称 <code>near real-time</code> 。默认是每隔 1 秒 refresh 一次的，所以 es 是准实时的，因为写入的数据 1 秒之后才能被看到。可以通过 es 的 <code>restful api</code> 或者 <code>java api</code> ，<strong>手动</strong>执行一次 refresh 操作，就是手动将 buffer 中的数据刷入 <code>os cache</code> 中，让数据立马就可以被搜索到。只要数据被输入 <code>os cache</code> 中，buffer 就会被清空了，因为不需要保留 buffer 了，数据在 translog 里面已经持久化到磁盘去一份了。</p><p>重复上面的步骤，新的数据不断进入 buffer 和 translog，不断将 <code>buffer</code> 数据写入一个又一个新的 <code>segment file</code> 中去，每次 <code>refresh</code> 完 buffer 清空，translog 保留。随着这个过程推进，translog 会变得越来越大。当 translog 达到一定长度的时候，就会触发 <code>commit</code> 操作。</p><p>commit 操作发生第一步，就是将 buffer 中现有数据 <code>refresh</code> 到 <code>os cache</code> 中去，清空 buffer。然后，将一个 <code>commit point</code> 写入磁盘文件，里面标识着这个 <code>commit point</code> 对应的所有 <code>segment file</code> ，同时强行将 <code>os cache</code> 中目前所有的数据都 <code>fsync</code> 到磁盘文件中去。最后<strong>清空</strong> 现有 translog 日志文件，重启一个 translog，此时 commit 操作完成。</p><p>这个 commit 操作叫做 <code>flush</code> 。默认 30 分钟自动执行一次 <code>flush</code> ，但如果 translog 过大，也会触发 <code>flush</code> 。flush 操作就对应着 commit 的全过程，我们可以通过 es api，手动执行 flush 操作，手动将 os cache 中的数据 fsync 强刷到磁盘上去。</p><p>translog 日志文件的作用是什么？你执行 commit 操作之前，数据要么是停留在 buffer 中，要么是停留在 os cache 中，无论是 buffer 还是 os cache 都是内存，一旦这台机器死了，内存中的数据就全丢了。所以需要将数据对应的操作写入一个专门的日志文件 <code>translog</code> 中，一旦此时机器宕机，再次重启的时候，es 会自动读取 translog 日志文件中的数据，恢复到内存 buffer 和 os cache 中去。</p><p>translog 其实也是先写入 os cache 的，默认每隔 5 秒刷一次到磁盘中去，所以默认情况下，可能有 5 秒的数据会仅仅停留在 buffer 或者 translog 文件的 os cache 中，如果此时机器挂了，会<strong>丢失</strong> 5 秒钟的数据。但是这样性能比较好，最多丢 5 秒的数据。也可以将 translog 设置成每次写操作必须是直接 <code>fsync</code> 到磁盘，但是性能会差很多。</p><p>实际上你在这里，如果面试官没有问你 es 丢数据的问题，你可以在这里给面试官炫一把，你说，其实 es 第一是准实时的，数据写入 1 秒后可以搜索到；可能会丢失数据的。有 5 秒的数据，停留在 buffer、translog os cache、segment file os cache 中，而不在磁盘上，此时如果宕机，会导致 5 秒的<strong>数据丢失</strong>。</p><p><strong>总结一下</strong>，数据先写入内存 buffer，然后每隔 1s，将数据 refresh 到 os cache，到了 os cache 数据就能被搜索到（所以我们才说 es 从写入到能被搜索到，中间有 1s 的延迟）。每隔 5s，将数据写入 translog 文件（这样如果机器宕机，内存数据全没，最多会有 5s 的数据丢失），translog 大到一定程度，或者默认每隔 30mins，会触发 commit 操作，将缓冲区的数据都 flush 到 segment file 磁盘文件中。</p><blockquote><p>数据写入 segment file 之后，同时就建立好了倒排索引。</p></blockquote><h3 id="es-如何在高并发环境下保证读写一致" tabindex="-1"><a class="header-anchor" href="#es-如何在高并发环境下保证读写一致" aria-hidden="true">#</a> ES 如何在高并发环境下保证读写一致？</h3><p><strong>乐观锁机制</strong> - 可以通过版本号使用乐观并发控制，以确保新版本不会被旧版本覆盖，由应用层来处理具体的冲突；</p><p>另外对于写操作，一致性级别支持 quorum/one/all，默认为 quorum，即只有当大多数分片可用时才允许写操作。但即使大多数可用，也可能存在因为网络等原因导致写入副本失败，这样该副本被认为故障，分片将会在一个不同的节点上重建。</p><p>对于读操作，可以设置 replication 为 sync（默认），这使得操作在主分片和副本分片都完成后才会返回；如果设置 replication 为 async 时，也可以通过设置搜索请求参数、_preference 为 primary 来查询主分片，确保文档是最新版本。</p><h3 id="什么是倒排索引" tabindex="-1"><a class="header-anchor" href="#什么是倒排索引" aria-hidden="true">#</a> 什么是倒排索引？</h3><figure><img src="https://miro.medium.com/v2/resize:fit:1100/format:webp/1*67BtkRv3KVjStbbK48HCYQ.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>举例来说，假设有以下文档：</p><table><thead><tr><th>DocId</th><th>Doc</th></tr></thead><tbody><tr><td>1</td><td>谷歌地图之父跳槽 Facebook</td></tr><tr><td>2</td><td>谷歌地图之父加盟 Facebook</td></tr><tr><td>3</td><td>谷歌地图创始人拉斯离开谷歌加盟 Facebook</td></tr><tr><td>4</td><td>谷歌地图之父跳槽 Facebook 与 Wave 项目取消有关</td></tr><tr><td>5</td><td>谷歌地图之父拉斯加盟社交网站 Facebook</td></tr></tbody></table><p>对文档进行分词之后，得到以下<strong>倒排索引</strong>。</p><table><thead><tr><th>WordId</th><th>Word</th><th>DocIds</th></tr></thead><tbody><tr><td>1</td><td>谷歌</td><td>1, 2, 3, 4, 5</td></tr><tr><td>2</td><td>地图</td><td>1, 2, 3, 4, 5</td></tr><tr><td>3</td><td>之父</td><td>1, 2, 4, 5</td></tr><tr><td>4</td><td>跳槽</td><td>1, 4</td></tr><tr><td>5</td><td>Facebook</td><td>1, 2, 3, 4, 5</td></tr><tr><td>6</td><td>加盟</td><td>2, 3, 5</td></tr><tr><td>7</td><td>创始人</td><td>3</td></tr><tr><td>8</td><td>拉斯</td><td>3, 5</td></tr><tr><td>9</td><td>离开</td><td>3</td></tr><tr><td>10</td><td>与</td><td>4</td></tr><tr><td>..</td><td>..</td><td>..</td></tr></tbody></table><p>另外，实用的倒排索引还可以记录更多的信息，比如文档频率信息，表示在文档集合中有多少个文档包含某个单词。</p><p>那么，有了倒排索引，搜索引擎可以很方便地响应用户的查询。比如用户输入查询 <code>Facebook</code> ，搜索系统查找倒排索引，从中读出包含这个单词的文档，这些文档就是提供给用户的搜索结果。</p><p>要注意倒排索引的两个重要细节：</p><ul><li>倒排索引中的所有词项对应一个或多个文档；</li><li>倒排索引中的词项<strong>根据字典顺序升序排列</strong></li></ul><h3 id="elasticsearch-中的倒排索引如何工作" tabindex="-1"><a class="header-anchor" href="#elasticsearch-中的倒排索引如何工作" aria-hidden="true">#</a> Elasticsearch 中的倒排索引如何工作？</h3><p>在搜索引擎中，每个文档都有一个对应的文档 ID，文档内容被表示为一系列关键词的集合。例如，文档 1 经过分词，提取了 20 个关键词，每个关键词都会记录它在文档中出现的次数和出现位置。那么，倒排索引就是<strong>关键词到文档</strong> ID 的映射，每个关键词都对应着一系列的文件，这些文件中都出现了关键词。</p><p>倒排索引，是通过分词策略，形成了词和文章的映射关系表，这种词典+映射表即为倒排索引。有了倒排索引，就能实现 o（1）时间复杂度的效率检索文章了，极大的提高了检索效率。</p><p>学术的解答方式：</p><p>倒排索引，相反于一篇文章包含了哪些词，它从词出发，记载了这个词在哪些文档中出现过，由两部分组成——词典和倒排表。</p><p>加分项：倒排索引的底层实现是基于：FST（Finite State Transducer）数据结构。</p><p>lucene 从 4+版本后开始大量使用的数据结构是 FST。FST 有两个优点：</p><p>（1）空间占用小。通过对词典中单词前缀和后缀的重复利用，压缩了存储空间；</p><p>（2）查询速度快。O(len(str)) 的查询时间复杂度。</p><h3 id="elasticsearch-中的倒排索引如何读写" tabindex="-1"><a class="header-anchor" href="#elasticsearch-中的倒排索引如何读写" aria-hidden="true">#</a> Elasticsearch 中的倒排索引如何读写？</h3><p>Elasticsearch 中的倒排索引其实是基于 Lucene 实现。</p><ul><li><p>Lucene 的写操作流程（索引），就是将原始文本进行分词，然后按倒排索引结构存储。</p></li><li><p>Lucene 的读操作流程（搜索），就是在倒排索引结构中进行检索，然后找到原始文档，返回结果。</p></li></ul><h3 id="字典树" tabindex="-1"><a class="header-anchor" href="#字典树" aria-hidden="true">#</a> 字典树</h3><p>常用字典数据结构如下所示：</p><figure><img src="https://pic2.zhimg.com/80/v2-8bb844c5b8fb944111fa8cecdb0e12d5_720w.jpg" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p>Trie 的核心思想是空间换时间，利用字符串的公共前缀来降低查询时间的开销以达到提高效率的目的。它有 3 个基本性质：</p><ul><li><p>根节点不包含字符，除根节点外每一个节点都只包含一个字符。</p></li><li><p>从根节点到某一节点，路径上经过的字符连接起来，为该节点对应的字符串。</p></li><li><p>每个节点的所有子节点包含的字符都不相同。</p></li></ul><figure><img src="https://pic4.zhimg.com/80/v2-26a48882a8f09a50dfeb79cc25045fcf_720w.jpg" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p>（1）可以看到，trie 树每一层的节点数是 26^i 级别的。所以为了节省空间，我们还可以用动态链表，或者用数组来模拟动态。而空间的花费，不会超过单词数 × 单词长度。</p><p>（2）实现：对每个结点开一个字母集大小的数组，每个结点挂一个链表，使用左儿子右兄弟表示法记录这棵树；</p><p>（3）对于中文的字典树，每个节点的子节点用一个哈希表存储，这样就不用浪费太大的空间，而且查询速度上可以保留哈希的复杂度 O(1)。</p><figure><img src="https://pic4.zhimg.com/80/v2-79f2a89041e546d9feccf55e4ff1c0d7_720w.jpg" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h2 id="elasticsearch-搜索" tabindex="-1"><a class="header-anchor" href="#elasticsearch-搜索" aria-hidden="true">#</a> Elasticsearch 搜索</h2><h3 id="es-查询速度为什么快" tabindex="-1"><a class="header-anchor" href="#es-查询速度为什么快" aria-hidden="true">#</a> ES 查询速度为什么快？</h3><ul><li><strong>倒排索引</strong> - Elasticsearch 查询速度快最核心的点在于使用倒排索引。 <ul><li>在 ES 中，为了提高查询效率，它对存储的文档进行了分词处理。分词是将连续的文本切分成一个个独立的词项的过程。对文本进行分词后，ES 会为每个词项创建一个倒排索引。这样，当用户进行查询时，ES 只需要在倒排索引中查找匹配的词项，从而快速地定位到相关的文档。</li><li>正向索引的结构是每个文档和关键字做关联，每个文档都有与之对应的关键字，记录关键字在文档中出现的位置和次数；而倒排索引则是将文档中的词项和文档的 ID 进行关联，这样就可以通过词项快速找到包含它的文档。</li></ul></li><li><strong>分片</strong> - Elasticsearch 通过分片，支持分布式存储和搜索，可以实现搜索的并行处理和负载均衡。</li></ul>',53),w={href:"https://cloud.tencent.com/developer/article/1922613",target:"_blank",rel:"noopener noreferrer"},S=d('<h3 id="es-有几种分页方式-各有什么特点" tabindex="-1"><a class="header-anchor" href="#es-有几种分页方式-各有什么特点" aria-hidden="true">#</a> ES 有几种分页方式？各有什么特点？</h3><p>Elasticsearch 支持三种分页查询方式。</p><ul><li>from + size - 可以使用 <code>from</code> 和 <code>size</code> 参数分别指定起始页和每页记录数。</li><li>search after - search after 搜索方式不支持指定页数，只能向下翻页；并且需要指定 sort，并保证值是唯一的。然后，可以反复使用上次结果中最后一个文档的 sort 值进行查询。</li><li>scroll - scroll 查询方式类似于 RDBMS 中的游标，只允许向下翻页。每次下一页查询后，使用返回结果的 scroll id 来作为下一次翻页的标记。scroll 查询会在搜索初始化阶段会生成快照，后续数据的变化无法及时体现在查询结果，因此更加适合一次性批量查询或非实时数据的分页查询。</li></ul><h3 id="es-为什么会有深分页问题" tabindex="-1"><a class="header-anchor" href="#es-为什么会有深分页问题" aria-hidden="true">#</a> ES 为什么会有深分页问题？</h3><p>在 Elasticsearch 中，搜索一般分为两个阶段，query 和 fetch 阶段。可以简单的理解，query 阶段确定要取哪些 doc，fetch 阶段取出具体的 doc。</p><ol><li>客户端发送请求到<strong>任意</strong>一个 node，这个 node 成为 <code>coordinate node</code>。<code>coordinate node</code> 创建一个大小为 from + size 的优先级队列用来存放结果。</li><li><code>coordinate node</code> 将请求广播到<strong>所有</strong>的 shard（<code>primary shard</code> 或 <code>replica shard</code> 都可以）。</li><li>query phase：每个 shard 在内部执行搜索请求，执行结果存到自身内部的大小同样为 from+size 的优先级队列里，然后将结果返回给 <code>coordinate node</code>，<code>coordinate node</code> 对数据进行汇总处理：合并、排序、分页，产生最终结果。</li><li>fetch phase：<code>coordinate node</code> 根据 <code>doc id</code> 去各个节点上 fetch（拉取）实际的 <code>document</code> 数据，最终返回给客户端。</li></ol><p>由以上流程可知：每个 shard 要扫描 from + size 条数据；而协调节点需要接收并处理 <code>(from + size) * primary_shard_num</code> 条数据量。一旦 from 或 size 过大，计算量也会很大，耗时很高。因此，ES 默认限制数据结果窗口大小为 10000（可以通过 <code>index.max_result_window</code> 调整）。</p><h3 id="如何解决-es-深分页问题" tabindex="-1"><a class="header-anchor" href="#如何解决-es-深分页问题" aria-hidden="true">#</a> 如何解决 ES 深分页问题？</h3><p>可以使用 search after 或 scroll 分页方式来解决深分页。</p>',9),k={href:"https://www.elastic.co/guide/en/elasticsearch/reference/current/paginate-search-results.html#search-after",target:"_blank",rel:"noopener noreferrer"},z=e("code",null,"search_after",-1),G=d('<h2 id="elasticsearch-聚合" tabindex="-1"><a class="header-anchor" href="#elasticsearch-聚合" aria-hidden="true">#</a> Elasticsearch 聚合</h2><h3 id="es-如何对海量数据-过亿-进行聚合计算" tabindex="-1"><a class="header-anchor" href="#es-如何对海量数据-过亿-进行聚合计算" aria-hidden="true">#</a> ES 如何对海量数据（过亿）进行聚合计算？</h3><p>Elasticsearch 提供的首个近似聚合是 cardinality 度量。它提供一个字段的基数，即该字段的 distinct 或者 unique 值的数目。它是基于 HLL 算法的。HLL 会先对我们的输入作哈希运算，然后根据哈希运算的结果中的 bits 做概率估算从而得到基数。其特点是：可配置的精度，用来控制内存的使用（更精确 ＝ 更多内存）；小的数据集精度是非常高的；我们可以通过配置参数，来设置去重需要的固定内存使用量。无论数千还是数十亿的唯一值，内存使用量只与你配置的精确度相关。</p><h2 id="elasticsearch-分析" tabindex="-1"><a class="header-anchor" href="#elasticsearch-分析" aria-hidden="true">#</a> Elasticsearch 分析</h2><h2 id="elasticsearch-复制" tabindex="-1"><a class="header-anchor" href="#elasticsearch-复制" aria-hidden="true">#</a> Elasticsearch 复制</h2><h3 id="es-是如何实现选主的" tabindex="-1"><a class="header-anchor" href="#es-是如何实现选主的" aria-hidden="true">#</a> ES 是如何实现选主的？</h3><p>限制条件：</p><ul><li><p>只有候选主节点才能成为主节点。</p></li><li><p>设置 <code>discovery.zen.minimum_master_nodes</code> 为 <code>N / 2 + 1</code>，当集群由于故障（如：通信失联）被分割成多个子集群时，节点数未达到半数以上的子集群，不允许进行选主。以此，来避免出现<strong>脑裂</strong>问题。</p></li></ul><p>选主流程：</p><ul><li><p>Elasticsearch 的选主是 ZenDiscovery 模块负责的，主要包含 Ping（节点之间通过这个 RPC 来发现彼此）和 Unicast（单播模块，包含一个主机列表以控制哪些节点需要 ping 通）这两部分；</p></li><li><p>对所有可以成为 master 的节点（node.master: true）根据 nodeId 字典排序，每次选举每个节点都把自己所知道节点排一次序，然后选出第一个（第 0 位）节点，暂且认为它是 master 节点。</p></li><li><p>如果对某个节点的投票数达到一定的值（可以成为 master 节点数 n/2+1）并且该节点自己也选举自己，那这个节点就是 master。否则重新选举一直到满足上述条件。</p></li><li><p>补充：master 节点的职责主要包括集群、节点和索引的管理，不负责文档级别的管理；data 节点可以关闭 http 功能。</p></li></ul><h3 id="es-如何避免脑裂问题" tabindex="-1"><a class="header-anchor" href="#es-如何避免脑裂问题" aria-hidden="true">#</a> ES 如何避免脑裂问题？</h3><h2 id="elasticsearch-分区" tabindex="-1"><a class="header-anchor" href="#elasticsearch-分区" aria-hidden="true">#</a> Elasticsearch 分区</h2><h3 id="es-是如何实现分区再均衡的" tabindex="-1"><a class="header-anchor" href="#es-是如何实现分区再均衡的" aria-hidden="true">#</a> ES 是如何实现分区再均衡的？</h3><figure><img src="https://raw.githubusercontent.com/dunwu/images/master/snap/202411221525828.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="elasticsearch-生产环境" tabindex="-1"><a class="header-anchor" href="#elasticsearch-生产环境" aria-hidden="true">#</a> Elasticsearch 生产环境</h2><h3 id="es-生产环境部署情况是怎样的" tabindex="-1"><a class="header-anchor" href="#es-生产环境部署情况是怎样的" aria-hidden="true">#</a> ES 生产环境部署情况是怎样的？</h3><p><strong>典型问题</strong></p><ul><li>你们的 Elasticsearch 生产环境部署情况是怎样的？</li><li>你们的 Elasticsearch 生产环境集群规模有多大？</li><li>你们的 Elasticsearch 生产环境中有多少索引，每个索引大概有多少个分片？</li></ul><p><strong>知识点</strong></p><p>根据实际 Elasticsearch 集群情况描述，以下是一个案例：</p><ul><li>节点数：19</li><li>索引数、分片数：1200+ 索引、1.6 万+ 分片</li><li>机器配置：6 核，10G 内存，800G 磁盘</li><li>容量：总容量 15TB，使用容量 10TB+</li><li>日增数据量：约 4 千万条数据，50 GB 增长容量</li></ul><h2 id="elasticsearch-优化" tabindex="-1"><a class="header-anchor" href="#elasticsearch-优化" aria-hidden="true">#</a> Elasticsearch 优化</h2><h3 id="filesystem-cache" tabindex="-1"><a class="header-anchor" href="#filesystem-cache" aria-hidden="true">#</a> filesystem cache</h3><p>你往 es 里写的数据，实际上都写到磁盘文件里去了，<strong>查询的时候</strong>，操作系统会将磁盘文件里的数据自动缓存到 <code>filesystem cache</code> 里面去。</p>',24),L={href:"https://github.com/doocs/advanced-java/blob/master/docs/high-concurrency/images/es-search-process.png",target:"_blank",rel:"noopener noreferrer"},q=e("img",{src:"https://github.com/doocs/advanced-java/raw/main/docs/high-concurrency/images/es-search-process.png",alt:"es-search-process",tabindex:"0",loading:"lazy"},null,-1),F=e("figcaption",null,"es-search-process",-1),I=d('<p>es 的搜索引擎严重依赖于底层的 <code>filesystem cache</code> ，你如果给 <code>filesystem cache</code> 更多的内存，尽量让内存可以容纳所有的 <code>idx segment file</code>索引数据文件，那么你搜索的时候就基本都是走内存的，性能会非常高。</p><p>性能差距究竟可以有多大？我们之前很多的测试和压测，如果走磁盘一般肯定上秒，搜索性能绝对是秒级别的，1 秒、5 秒、10 秒。但如果是走 <code>filesystem cache</code> ，是走纯内存的，那么一般来说性能比走磁盘要高一个数量级，基本上就是毫秒级的，从几毫秒到几百毫秒不等。</p><p>这里有个真实的案例。某个公司 es 节点有 3 台机器，每台机器看起来内存很多，64G，总内存就是 <code>64 * 3 = 192G</code> 。每台机器给 es jvm heap 是 <code>32G</code> ，那么剩下来留给 <code>filesystem cache</code> 的就是每台机器才 <code>32G</code> ，总共集群里给 <code>filesystem cache</code> 的就是 <code>32 * 3 = 96G</code> 内存。而此时，整个磁盘上索引数据文件，在 3 台机器上一共占用了 <code>1T</code> 的磁盘容量，es 数据量是 <code>1T</code> ，那么每台机器的数据量是 <code>300G</code> 。这样性能好吗？ <code>filesystem cache</code> 的内存才 100G，十分之一的数据可以放内存，其他的都在磁盘，然后你执行搜索操作，大部分操作都是走磁盘，性能肯定差。</p><p>归根结底，你要让 es 性能要好，最佳的情况下，就是你的机器的内存，至少可以容纳你的总数据量的一半。</p><p>根据我们自己的生产环境实践经验，最佳的情况下，是仅仅在 es 中就存少量的数据，就是你要<strong>用来搜索的那些索引</strong>，如果内存留给 <code>filesystem cache</code> 的是 100G，那么你就将索引数据控制在 <code>100G</code> 以内，这样的话，你的数据几乎全部走内存来搜索，性能非常之高，一般可以在 1 秒以内。</p><p>比如说你现在有一行数据。 <code>id,name,age ....</code> 30 个字段。但是你现在搜索，只需要根据 <code>id,name,age</code> 三个字段来搜索。如果你傻乎乎往 es 里写入一行数据所有的字段，就会导致说 <code>90%</code> 的数据是不用来搜索的，结果硬是占据了 es 机器上的 <code>filesystem cache</code> 的空间，单条数据的数据量越大，就会导致 <code>filesystem cahce</code> 能缓存的数据就越少。其实，仅仅写入 es 中要用来检索的<strong>少数几个字段</strong>就可以了，比如说就写入 es <code>id,name,age</code> 三个字段，然后你可以把其他的字段数据存在 mysql/hbase 里，我们一般是建议用 <code>es + hbase</code> 这么一个架构。</p><p>hbase 的特点是<strong>适用于海量数据的在线存储</strong>，就是对 hbase 可以写入海量数据，但是不要做复杂的搜索，做很简单的一些根据 id 或者范围进行查询的这么一个操作就可以了。从 es 中根据 name 和 age 去搜索，拿到的结果可能就 20 个 <code>doc id</code> ，然后根据 <code>doc id</code> 到 hbase 里去查询每个 <code>doc id</code> 对应的<strong>完整的数据</strong>，给查出来，再返回给前端。</p><p>写入 es 的数据最好小于等于，或者是略微大于 es 的 filesystem cache 的内存容量。然后你从 es 检索可能就花费 20ms，然后再根据 es 返回的 id 去 hbase 里查询，查 20 条数据，可能也就耗费个 30ms，可能你原来那么玩儿，1T 数据都放 es，会每次查询都是 5~10s，现在可能性能就会很高，每次查询就是 50ms。</p><h3 id="数据预热" tabindex="-1"><a class="header-anchor" href="#数据预热" aria-hidden="true">#</a> 数据预热</h3><p>假如说，哪怕是你就按照上述的方案去做了，es 集群中每个机器写入的数据量还是超过了 <code>filesystem cache</code> 一倍，比如说你写入一台机器 60G 数据，结果 <code>filesystem cache</code> 就 30G，还是有 30G 数据留在了磁盘上。</p><p>其实可以做<strong>数据预热</strong>。</p><p>举个例子，拿微博来说，你可以把一些大 V，平时看的人很多的数据，你自己提前后台搞个系统，每隔一会儿，自己的后台系统去搜索一下热数据，刷到 <code>filesystem cache</code> 里去，后面用户实际上来看这个热数据的时候，他们就是直接从内存里搜索了，很快。</p><p>或者是电商，你可以将平时查看最多的一些商品，比如说 iphone 8，热数据提前后台搞个程序，每隔 1 分钟自己主动访问一次，刷到 <code>filesystem cache</code> 里去。</p><p>对于那些你觉得比较热的、经常会有人访问的数据，最好<strong>做一个专门的缓存预热子系统</strong>，就是对热数据每隔一段时间，就提前访问一下，让数据进入 <code>filesystem cache</code> 里面去。这样下次别人访问的时候，性能一定会好很多。</p><h3 id="冷热分离" tabindex="-1"><a class="header-anchor" href="#冷热分离" aria-hidden="true">#</a> 冷热分离</h3><p>es 可以做类似于 mysql 的水平拆分，就是说将大量的访问很少、频率很低的数据，单独写一个索引，然后将访问很频繁的热数据单独写一个索引。最好是将<strong>冷数据写入一个索引中，然后热数据写入另外一个索引中</strong>，这样可以确保热数据在被预热之后，尽量都让他们留在 <code>filesystem os cache</code> 里，<strong>别让冷数据给冲刷掉</strong>。</p><p>你看，假设你有 6 台机器，2 个索引，一个放冷数据，一个放热数据，每个索引 3 个 shard。3 台机器放热数据 index，另外 3 台机器放冷数据 index。然后这样的话，你大量的时间是在访问热数据 index，热数据可能就占总数据量的 10%，此时数据量很少，几乎全都保留在 <code>filesystem cache</code> 里面了，就可以确保热数据的访问性能是很高的。但是对于冷数据而言，是在别的 index 里的，跟热数据 index 不在相同的机器上，大家互相之间都没什么联系了。如果有人访问冷数据，可能大量数据是在磁盘上的，此时性能差点，就 10% 的人去访问冷数据，90% 的人在访问热数据，也无所谓了。</p><h3 id="document-模型设计" tabindex="-1"><a class="header-anchor" href="#document-模型设计" aria-hidden="true">#</a> document 模型设计</h3><p>对于 MySQL，我们经常有一些复杂的关联查询。在 es 里该怎么玩儿，es 里面的复杂的关联查询尽量别用，一旦用了性能一般都不太好。</p><p>最好是先在 Java 系统里就完成关联，将关联好的数据直接写入 es 中。搜索的时候，就不需要利用 es 的搜索语法来完成 join 之类的关联搜索了。</p><p>document 模型设计是非常重要的，很多操作，不要在搜索的时候才想去执行各种复杂的乱七八糟的操作。es 能支持的操作就那么多，不要考虑用 es 做一些它不好操作的事情。如果真的有那种操作，尽量在 document 模型设计的时候，写入的时候就完成。另外对于一些太复杂的操作，比如 join/nested/parent-child 搜索都要尽量避免，性能都很差的。</p><h3 id="分页性能优化" tabindex="-1"><a class="header-anchor" href="#分页性能优化" aria-hidden="true">#</a> 分页性能优化</h3><p>es 的分页是较坑的，为啥呢？举个例子吧，假如你每页是 10 条数据，你现在要查询第 100 页，实际上是会把每个 shard 上存储的前 1000 条数据都查到一个协调节点上，如果你有个 5 个 shard，那么就有 5000 条数据，接着协调节点对这 5000 条数据进行一些合并、处理，再获取到最终第 100 页的 10 条数据。</p><p>分布式的，你要查第 100 页的 10 条数据，不可能说从 5 个 shard，每个 shard 就查 2 条数据，最后到协调节点合并成 10 条数据吧？你<strong>必须</strong>得从每个 shard 都查 1000 条数据过来，然后根据你的需求进行排序、筛选等等操作，最后再次分页，拿到里面第 100 页的数据。你翻页的时候，翻的越深，每个 shard 返回的数据就越多，而且协调节点处理的时间越长，非常坑爹。所以用 es 做分页的时候，你会发现越翻到后面，就越是慢。</p><p>我们之前也是遇到过这个问题，用 es 作分页，前几页就几十毫秒，翻到 10 页或者几十页的时候，基本上就要 5~10 秒才能查出来一页数据了。</p><p>有什么解决方案吗？</p><h4 id="不允许深度分页-默认深度分页性能很差" tabindex="-1"><a class="header-anchor" href="#不允许深度分页-默认深度分页性能很差" aria-hidden="true">#</a> 不允许深度分页（默认深度分页性能很差）</h4><p>跟产品经理说，你系统不允许翻那么深的页，默认翻的越深，性能就越差。</p><h4 id="类似于-app-里的推荐商品不断下拉出来一页一页的" tabindex="-1"><a class="header-anchor" href="#类似于-app-里的推荐商品不断下拉出来一页一页的" aria-hidden="true">#</a> 类似于 app 里的推荐商品不断下拉出来一页一页的</h4><p>类似于微博中，下拉刷微博，刷出来一页一页的，你可以用 <code>scroll api</code> ，关于如何使用，自行上网搜索。</p><p>scroll 会一次性给你生成<strong>所有数据的一个快照</strong>，然后每次滑动向后翻页就是通过<strong>游标</strong> <code>scroll_id</code> 移动，获取下一页下一页这样子，性能会比上面说的那种分页性能要高很多很多，基本上都是毫秒级的。</p><p>但是，唯一的一点就是，这个适合于那种类似微博下拉翻页的，<strong>不能随意跳到任何一页的场景</strong>。也就是说，你不能先进入第 10 页，然后去第 120 页，然后又回到第 58 页，不能随意乱跳页。所以现在很多产品，都是不允许你随意翻页的，app，也有一些网站，做的就是你只能往下拉，一页一页的翻。</p><p>初始化时必须指定 <code>scroll</code> 参数，告诉 es 要保存此次搜索的上下文多长时间。你需要确保用户不会持续不断翻页翻几个小时，否则可能因为超时而失败。</p><p>除了用 <code>scroll api</code> ，你也可以用 <code>search_after</code> 来做， <code>search_after</code> 的思想是使用前一页的结果来帮助检索下一页的数据，显然，这种方式也不允许你随意翻页，你只能一页页往后翻。初始化时，需要使用一个唯一值的字段作为 sort 字段。</p><p><strong>1.1、设计阶段调优</strong></p><p>（1）根据业务增量需求，采取基于日期模板创建索引，通过 roll over API 滚动索引；</p><p>（2）使用别名进行索引管理；</p><p>（3）每天凌晨定时对索引做 force_merge 操作，以释放空间；</p><p>（4）采取冷热分离机制，热数据存储到 SSD，提高检索效率；冷数据定期进行 shrink 操作，以缩减存储；</p><p>（5）采取 curator 进行索引的生命周期管理；</p><p>（6）仅针对需要分词的字段，合理的设置分词器；</p><p>（7）Mapping 阶段充分结合各个字段的属性，是否需要检索、是否需要存储等。……..</p><p><strong>1.2、写入调优</strong></p><p>（1）写入前副本数设置为 0；</p><p>（2）写入前关闭 refresh_interval 设置为-1，禁用刷新机制；</p><p>（3）写入过程中：采取 bulk 批量写入；</p><p>（4）写入后恢复副本数和刷新间隔；</p><p>（5）尽量使用自动生成的 id。</p><p>1.3、查询调优</p><p>（1）禁用 wildcard；</p><p>（2）禁用批量 terms（成百上千的场景）；</p><p>（3）充分利用倒排索引机制，能 keyword 类型尽量 keyword；</p><p>（4）数据量大时候，可以先基于时间敲定索引再检索；</p><p>（5）设置合理的路由机制。</p><p>1.4、其他调优</p><p>部署调优，业务调优等。</p><p>上面的提及一部分，面试者就基本对你之前的实践或者运维经验有所评估了。</p><h3 id="查询优化" tabindex="-1"><a class="header-anchor" href="#查询优化" aria-hidden="true">#</a> 查询优化</h3><h3 id="服务器优化" tabindex="-1"><a class="header-anchor" href="#服务器优化" aria-hidden="true">#</a> 服务器优化</h3><h4 id="elasticsearch-gc-需要注意什么" tabindex="-1"><a class="header-anchor" href="#elasticsearch-gc-需要注意什么" aria-hidden="true">#</a> Elasticsearch GC 需要注意什么？</h4><ul><li><p>倒排索引的词典需要常驻内存，无法 GC，需要监控 data node 上 segment memory(filesystem cache) 增长趋势。</p></li><li><p>各类缓存，field cache, filter cache, indexing cache, bulk queue 等等，要设置合理的大小，并且要应该根据最坏的情况来看 heap 是否够用，也就是各类缓存全部占满的时候，还有 heap 空间可以分配给其他任务吗？避免采用 clear cache 等“自欺欺人”的方式来释放内存。</p></li><li><p>避免返回大量结果集的搜索与聚合。确实需要大量拉取数据的场景，可以采用 scan &amp; scroll api 来实现。</p></li><li><p>cluster stats 驻留内存并无法水平扩展，超大规模集群可以考虑分拆成多个集群通过 tribe node 连接。</p></li><li><p>想知道 heap 够不够，必须结合实际应用场景，并对集群的 heap 使用情况做持续的监控。</p></li><li><p>根据监控数据理解内存需求，合理配置各类 circuit breaker，将内存溢出风险降低到最低</p></li></ul><h3 id="硬件优化" tabindex="-1"><a class="header-anchor" href="#硬件优化" aria-hidden="true">#</a> 硬件优化</h3><h4 id="elasticsearch-在部署时-对-linux-的设置有哪些优化方法" tabindex="-1"><a class="header-anchor" href="#elasticsearch-在部署时-对-linux-的设置有哪些优化方法" aria-hidden="true">#</a> Elasticsearch 在部署时，对 Linux 的设置有哪些优化方法</h4><p><strong>知识点</strong></p><ul><li><p>关闭缓存 swap;</p></li><li><p>堆内存设置为：Min（节点内存/2, 32GB）;</p></li><li><p>设置最大文件句柄数；</p></li><li><p>线程池+队列大小根据业务需要做调整；</p></li><li><p>磁盘存储 raid 方式——存储有条件使用 RAID10，增加单节点性能以及避免单节点存储故障。</p></li></ul><h3 id="综合优化" tabindex="-1"><a class="header-anchor" href="#综合优化" aria-hidden="true">#</a> 综合优化</h3><h4 id="es-索引数据多-如何优化" tabindex="-1"><a class="header-anchor" href="#es-索引数据多-如何优化" aria-hidden="true">#</a> ES 索引数据多，如何优化？</h4><p><strong>知识点</strong></p><ul><li><strong>动态索引</strong> - 如果单索引数据量过大，可以创建索引模板，并周期性创建新索引（举例来说，索引名为 blog_yyyyMMdd），实现数据的分解。</li><li><strong>冷热数据分离</strong> - 将一定范围（如：一周、一月等）的数据作为热数据，其他数据作为冷数据。针对冷数据，可以考虑定期 force_merge + shrink 进行压缩，以节省存储空间和检索效率。</li><li><strong>分区再均衡</strong> - Elasticsearch 集群可以动态根据节点数的变化，调整索引分片在集群上的分布。但需要注意的是，要提前合理规划好索引的分片数：分片数过少，则增加节点也无法水平扩展；分片数过多，影响 Elasticsearch 读写效率。</li></ul>',69);function T(j,B){const c=t("ExternalLinkIcon");return o(),i("div",null,[l,e("p",null,[e("strong",null,[e("a",h,[a("Elasticsearch"),r(c)]),a(" 是一个开源的分布式搜索和分析引擎")]),a("。")]),e("p",null,[e("strong",null,[e("a",p,[a("Elasticsearch"),r(c)]),a(" 基于搜索库 "),e("a",g,[a("Lucene"),r(c)]),a(" 开发")]),a("。ElasticSearch 隐藏了 Lucene 的复杂性，提供了简单易用的 REST API / Java API 接口（另外还有其他语言的 API 接口）。")]),f,e("blockquote",null,[u,e("ul",null,[e("li",null,[e("a",m,[a("https://www.elastic.co/guide/en/elasticsearch/reference/current/preload-data-to-file-system-cache.html"),r(c)])]),e("li",null,[e("a",b,[a("https://blog.devgenius.io/elasticsearch-solution-to-searching-71116220c82f"),r(c)])])])]),_,e("figure",null,[e("a",x,[y,r(c)]),E]),v,e("blockquote",null,[e("p",null,[a("参考："),e("a",w,[a("https://cloud.tencent.com/developer/article/1922613"),r(c)])])]),S,e("p",null,[a("Elasticsearch 官方不再建议使用 scroll 查询方式进行深分页，而是推荐使用 "),e("a",k,[z,r(c)]),a(" 和时间点（PIT）一起使用。")]),G,e("figure",null,[e("a",L,[q,r(c)]),F]),I])}const C=s(n,[["render",T],["__file","index.html.vue"]]);export{C as default};
